package common

import (
	"testing"

	"github.com/stretchr/testify/require"
)

func TestEnum_PREFLIGHT_CALIBRATION_MAGNETOMETER(t *testing.T) {
	t.Run("zero", func(t *testing.T) {
		var e PREFLIGHT_CALIBRATION_MAGNETOMETER
		e.UnmarshalText([]byte{})
		e.MarshalText()
		e.String()
	})

	t.Run("first entry", func(t *testing.T) {
		enc, err := PREFLIGHT_CALIBRATION_MAGNETOMETER_NONE.MarshalText()
		require.NoError(t, err)

		var dec PREFLIGHT_CALIBRATION_MAGNETOMETER
		err = dec.UnmarshalText(enc)
		require.NoError(t, err)

		require.Equal(t, PREFLIGHT_CALIBRATION_MAGNETOMETER_NONE, dec)
	})
}
